export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<string, NotificationAdapter> = new Map();
  private preferencesService?: PreferencesService;
  private historyService?: NotificationHistoryService;
  private queue: Array<{
    params: {
      type: NotificationType;
      userId?: string;
      recipient: string;
      subject: string;
      body: string;
      channel: NotificationChannel;
      metadata?: Record<string, unknown>;
    };
    resolve: (value: Notification | null) => void;
    reject: (error: unknown) => void;
  }> = [];
  private processing = false;

  constructor(
    private eventBus: EventBus,
    adapters: NotificationAdapter[] = [],
    preferencesService?: PreferencesService,
    historyService?: NotificationHistoryService,
  ) {
    for (const adapter of adapters) {
      this.adapters.set(adapter.channel, adapter);
    }
    this.preferencesService = preferencesService;
    this.historyService = historyService;
    this.registerEventHandlers();
  }

