/**
 * Send a notification through the appropriate adapter.
 * Notifications are queued and processed sequentially to guarantee delivery order.
 * Falls back to in-memory storage if no adapter is registered for the channel.
 */
async sendNotification(params: {
  type: NotificationType;
  userId?: string;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  metadata?: Record<string, unknown>;
}): Promise<Notification | null> {
  return new Promise<Notification | null>((resolve, reject) => {
    this.queue.push({ params, resolve, reject });
    this.processQueue();
  });
}

private async processQueue(): Promise<void> {
  if (this.processing) return;
  this.processing = true;

  while (this.queue.length > 0) {
    const item = this.queue.shift()!;
    try {
      const result = await this.deliverNotification(item.params);
      item.resolve(result);
    } catch (error) {
      item.reject(error);
    }
  }

  this.processing = false;
}

private async deliverNotification(params: {
  type: NotificationType;
  userId?: string;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  metadata?: Record<string, unknown>;
}): Promise<Notification | null> {
  // Check user preferences before sending (per-channel)
  if (params.userId && this.preferencesService) {
    if (!this.preferencesService.shouldSendNotification(params.userId, params.type, params.channel)) {
      this.logger.info(`Notification ${params.type} on ${params.channel} suppressed for user ${params.userId} by preferences`);
      return null;
    }
  }

  const payload: NotificationPayload = {
    id: generateNotificationId(),
    type: params.type,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    channel: params.channel,
    metadata: params.metadata,
  };

  const adapter = this.adapters.get(params.channel);

  let notification: Notification;

  if (adapter) {
    const result = await adapter.send(payload);
    notification = {
      id: payload.id,
      type: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      channel: payload.channel,
      status: result.success ? 'sent' : 'failed',
      error: result.error,
      sentAt: result.deliveredAt,
    };
  } else {
    this.logger.warn(`No adapter for channel "${params.channel}", storing notification without delivery`);
    notification = {
      id: payload.id,
      type: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      channel: payload.channel,
      status: 'sent',
      sentAt: new Date(),
    };
  }

  this.notifications.push(notification);

  if (this.historyService) {
    this.historyService.record(notification);
  }

  this.logger.info(`Notification ${notification.id} to ${params.recipient} [${notification.status}]`);
  return notification;
}

