import type { NotificationAdapter } from '../../src/adapters/notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../../src/models/notification.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

/**
 * Adapter with configurable delay per call, used to verify ordering guarantees.
 */
class DelayAdapter implements NotificationAdapter {
  readonly channel = 'email';
  public deliveries: string[] = [];
  private delays: number[];
  private callIndex = 0;

  constructor(delays: number[]) {
    this.delays = delays;
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    const delay = this.delays[this.callIndex++] ?? 0;
    await new Promise((r) => setTimeout(r, delay));
    this.deliveries.push(payload.id);
    return {
      success: true,
      notificationId: payload.id,
      channel: 'email',
      deliveredAt: new Date(),
    };
  }
}

describe('NotificationService', () => {

    it('should not check preferences when userId is not provided', async () => {
      preferencesService.updatePreferences('user-1', {
        channelPreferences: { email: { enabled: false }, sms: { enabled: false } },
      });

      // No userId — preferences are not checked
      const result = await multiChannelService.sendNotification({
        type: 'system_alert',
        recipient: 'admin@example.com',
        subject: 'Alert',
        body: 'System alert',
        channel: 'email',
      });

      expect(result).not.toBeNull();
    });
  });

  describe('notification ordering', () => {
    it('should deliver notifications in order even when dispatched concurrently', async () => {
      // First notification has a longer adapter delay than the second.
      // Without a queue, the second would arrive before the first.
      const delayAdapter = new DelayAdapter([50, 0]);
      const orderedService = new NotificationService(eventBus, [delayAdapter]);
      resetNotificationIdCounter();

      // Fire both without awaiting — simulates concurrent event emission
      const p1 = orderedService.sendNotification({
        type: 'order_confirmation',
        recipient: 'alice@example.com',
        subject: 'Order Placed',
        body: 'Your order has been placed.',
        channel: 'email',
      });
      const p2 = orderedService.sendNotification({
        type: 'order_status_update',
        recipient: 'alice@example.com',
        subject: 'Payment Confirmed',
        body: 'Your payment has been confirmed.',
        channel: 'email',
      });

      const [n1, n2] = await Promise.all([p1, p2]);

      // Both should be delivered
      expect(n1).not.toBeNull();
      expect(n2).not.toBeNull();

      // Adapter should have received them in submission order, not completion-time order
      expect(delayAdapter.deliveries).toEqual(['notif-0001', 'notif-0002']);

      // In-memory notifications list should also be in order
      const notifications = orderedService.getNotifications();
      expect(notifications[0]?.subject).toBe('Order Placed');
      expect(notifications[1]?.subject).toBe('Payment Confirmed');
    });

    it('should preserve order across concurrent event bus emissions', async () => {
      const delayAdapter = new DelayAdapter([30, 0]);
      const orderedService = new NotificationService(eventBus, [delayAdapter]);
      resetNotificationIdCounter();

      // Emit order:created and order:status-changed concurrently (no await between them)
      const createdEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      const statusEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      // Fire concurrently — this is the scenario that caused out-of-order delivery
      await Promise.all([
        eventBus.emit(createdEvent),
        eventBus.emit(statusEvent),
      ]);

      const notifications = orderedService.getNotifications();
      expect(notifications).toHaveLength(2);
      expect(notifications[0]?.type).toBe('order_confirmation');
      expect(notifications[1]?.type).toBe('order_status_update');
    });
  });
});

